  {if is_nil(filament_retract_length_toolchange[current_extruder])}
  G1 E-[retract_length[current_extruder]] F{retract_speed[current_extruder] * 60}
  {endif}

  G1 F{speed_tc}
  M204 S7000

{if not (layer_num < 0 and next_extruder == initial_tool)}
    G27 W3 Z{travel_max_lift[current_extruder]} P2 R{retract_toolchange} V{retract_speed[current_extruder]} A{travel_slope[current_extruder]}

