  {endif}

  T{next_extruder} S1 L0 D0
  [start_filament_gcode]

  {local target_temp = temperature[next_extruder]}

  {if layer_z <= (first_layer_height + 0.0001)}
    {target_temp = first_layer_temperature[next_extruder]}
  {endif}

  M104 S{target_temp}

  G12 S90 ; enter cleaner
  G12 S30 ; eject poop

  M106 S{255 / 100 * max_fan_speed[next_extruder]}
  M109 S{target_temp}

  M906 P1 ; Set extruder current
  M83

  {if is_nil(filament_retract_length_toolchange[next_extruder])}
  G1 E{retract_toolchange + retract_length[next_extruder]} F{20 * 60}
  {else}
  G1 E{retract_toolchange + filament_retract_length_toolchange[next_extruder]} F{20 * 60}
  {endif}

  M400

  M201 E{default_acceleration * extrusion_width * layer_height / (3.14 * filament_diameter[next_extruder] * filament_diameter[next_extruder] / 4)}

