  G1 Y1.5 E{(0.3 * filament_minimal_purge_on_wipe_tower[current_extruder]) / (3.14 * filament_diameter[next_extruder] * filament_diameter[next_extruder] / 4)} F{min(250, 60*filament_max_volumetric_speed[next_extruder]/3.14/filament_diameter[next_extruder]/filament_diameter[next_extruder]*4)}

  G90 ; use absolute coordinates
  M83 ; extruder relative mode
  ;FLUSH_END

  M201 E[machine_max_acceleration_e]
  M906 P0 ; Revert extruder current
  M400

  G1 E-{1.5 * retract_length[next_extruder]} F{retract_speed[next_extruder] * 60}
  {e_retracted[next_extruder] = 1.5 * retract_length[next_extruder]}
  M400

  G1 F{speed_tc}

  G12 S91 ; Exit cleaning station

  G0 Z{layer_z + 1} ; Lift

  {if layer_z <= (first_layer_height + (disable_fan_first_layers[next_extruder] - 1) * layer_height + 0.0001)}
    M106 S0
  {endif}

  G1 F{speed_tc}

{else}

  {if previous_extruder != -1}
    ; wipe tower enabled
    ; Change Tool[previous_extruder] -> Tool[next_extruder] (layer [layer_num])

  {if is_nil(filament_retract_length_toolchange[current_extruder])}
